sp_widget.client_script:
api.controller=function($window,$location) {
  /* widget controller */
  var c = this;
	//alert(window.location.origin.toString().indexOf('ping-now.com')>=0);

	c.goBack = function() {
    //$window.history.back();
		$location.url('?id=incentive_statements');
  };
};

sp_widget.css:
.headd {
	  font-size: 2.6rem;
    font-weight: 700;
    color: #0f172a;
}

.ip-header {
	  padding: 1rem;
    margin-bottom: 2rem;
}
.admin-page-topbar {
  display: flex;
  align-items: center;
  gap: 14px;
  //margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 1px solid #e2e8f0;
}

.admin-back-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: #ffffff;
  border: 1.5px solid #e2e8f0;
  cursor: pointer;
  color: #374151;
  flex-shrink: 0;
  transition: background 0.15s, border-color 0.15s;
}
.admin-back-btn:hover {
  background: #f1f5f9;
  border-color: #94a3b8;
}

